<?php
require_once __DIR__ . '/BaseController.php'; require_once __DIR__ . '/../models/Outlet.php'; require_once __DIR__ . '/../models/ActivityLog.php';
class OutletController extends BaseController { public function index(): void { $this->requireLogin();$kode_outlet=$_SESSION['kode_outlet'];$nama_outlet=$_SESSION['nama_outlet'];$model=new Outlet();$log=new ActivityLog();$swal_script='';if(isset($_POST['simpan_penjualan'])){$name=$model->recordSale($kode_outlet,(int)$_POST['id_menu'],(int)$_POST['qty'],$_POST['catatan_rasa']??'');if($name){$log->add($kode_outlet,'Catat Penjualan','Menjual penjualan offline: '.$name);$swal_script="Swal.fire('Berhasil!', 'Penjualan dicatat & Stok berkurang!', 'success').then(() => window.location.href='admin-stok.php');";}}elseif(isset($_POST['ubah_status'])){$model->setStatus($kode_outlet,$_POST['status_toko']??'tutup');$log->add($kode_outlet,'Ubah Status Toko','Status toko diperbarui');$swal_script="Swal.fire('Tersimpan!', 'Status outlet berhasil diubah!', 'success').then(() => window.location.href='admin-stok.php');";}elseif(isset($_POST['update_stok'])){$name=$model->updateStock($kode_outlet,(int)$_POST['id_menu'],(int)$_POST['stok_baru']);if($name){$log->add($kode_outlet,'Update Stok',"Ubah stok $name");$swal_script="Swal.fire('Stok Diupdate!', '', 'success').then(() => window.location.href='admin-stok.php');";}}elseif(isset($_POST['kirim_request'])){$ok=$model->requestStock($nama_outlet,$_POST['nama_barang']??'',(int)$_POST['jumlah'],$_POST['satuan']??'Pcs');$swal_script=$ok?"Swal.fire('Terkirim!', 'Permintaan restock sudah dikirim ke Gudang Pusat.', 'success').then(() => window.location.href='admin-stok.php');":"Swal.fire('Gagal!', 'Gagal mengirim permintaan.', 'error');";}$status_sekarang=$model->status($kode_outlet);$menus=$model->menus();$salesHistory=$model->salesHistory($kode_outlet);$this->view('outlet',compact('kode_outlet','nama_outlet','swal_script','status_sekarang','menus','salesHistory')); }
 public function requestHistory(): void { $this->requireLogin();$requestHistory=(new Outlet())->requestHistory($_SESSION['nama_outlet']);$this->view('request-history',compact('requestHistory')); } }
